```hcl
resource "aws_security_group" "<example_resource_name>" {
  name   = "<example_resource_name>"
  vpc_id = "<example_resource_id>"

  # CRITICAL: Do not use 0.0.0.0/0 or ::/0; restrict these ports to trusted CIDRs
  ingress {
    from_port   = 9200
    to_port     = 9200
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]  # CRITICAL: restricts 9200 from Internet
  }
